import i18n from "i18next";
import { initReactI18next } from "react-i18next";
import LanguageDetector from "i18next-browser-languagedetector";

i18n
  .use(LanguageDetector) // detects system/browser language
  .use(initReactI18next) // passes i18n down to react-i18next
  .init({
    fallbackLng: "en", // default language if none detected
    debug: true,
    interpolation: {
      escapeValue: false, // react already escapes
    },
    resources: {
    en: { translation: require("/public/locales/en/translation.json") },
    sp: { translation: require("/public/locales/sp/translation.json") },
    pt: { translation: require("/public/locales/pt/translation.json") },
    }
  });

export default i18n;
